mapper.update:
UPDATE chat_room
SET    status = #{status}
WHERE  chat_room_id = #{chatRoomId}

mapper.select:
SELECT COUNT(*) FROM chat_room
WHERE  chat_room_type = #{type}
AND    status = 'ACTIVE'

mapper.update:
UPDATE chat_member
SET    admin_status = #{adminStatus}
WHERE  chat_room_id = #{chatRoomId}
AND    member_id    = #{memberId}

mapper.select:
SELECT * FROM ( SELECT msg.message_id AS messageId, msg.room_id AS roomId, msg.member_id AS memberId, m2.nickname AS senderNickname, msg.message_type AS messageType, msg.content, TO_CHAR(msg.created_at, 'YYYY-MM-DD HH24:MI') AS createdAt FROM chat_message msg LEFT JOIN member1 m ON m.member_id = msg.member_id LEFT JOIN member2 m2 ON m2.member_id = msg.member_id WHERE msg.room_id = #{chatRoomId}
AND TRUNC(msg.created_at) = TO_DATE(#{searchDate}, 'YYYY-MM-DD')
ORDER BY msg.created_at DESC ) WHERE ROWNUM <= #{size} ORDER BY messageId ASC
